(()=>{var n=document.querySelector("nav"),r=n.querySelector("ul"),a=document.querySelector("#burger-template").content.cloneNode(!0),t=a.querySelector("button[data-btn-drawer]");r.style.setProperty("display","flex");t.addEventListener("click",e=>{let o=t.getAttribute("aria-expanded")==="true";t.setAttribute("aria-expanded",!o)});var d=()=>{t.setAttribute("aria-expanded",!1)};document.addEventListener("keyup",e=>{e.code==="Escape"&&d()});document.addEventListener("click",e=>{n.contains(e.target)||d()});document.addEventListener("DOMContentLoaded",function(){setTimeout(()=>{r.removeAttribute("data-no-flash")},100)});n.insertBefore(a,r);})();